import{_ as i,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Find your Device IDs","description":"","frontmatter":{"title":"Find your Device IDs","slug":"how-do-i-find-my-device-ids"},"headers":[],"relativePath":"account-hub/how-do-i-find-my-device-ids.md","filePath":"account-hub/how-do-i-find-my-device-ids.md"}'),r={name:"account-hub/how-do-i-find-my-device-ids.md"};function d(s,e,a,l,c,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<p>Both iOS and Android devices have unique, semi-persistent identifiers, which are used to help advertisers (and a variety of other entities) track the activity on those devices. These identifiers also help Branch provide accurate analytics and deep linking to our customers.</p><p>On iOS, the identifier in question is the IDFA, or Identity for Advertising. The Android Advertising Identifier is the Android analog.</p><p>Neither identifier is particularly easy to find, and both can be reset. While these IDs are unique, they aren&#39;t persistent; as with cookies on the web, users ultimately have control over whether they can be tracked using these identifiers.</p><p>Find out how to find and reset your device identifier on iOS and Android below.</p><h2 id="find-my-apple-device-id" tabindex="-1">Find my Apple device ID <a class="header-anchor" href="#find-my-apple-device-id" aria-label="Permalink to &quot;Find my Apple device ID&quot;">​</a></h2><p>Apple does not currently provide a built-in way for users to directly view their IDFA. To do this, you&#39;ll need to use a third-party app from the App Store.</p><p>However, you can reset your IDFA if you need to. To do this:</p><ol><li><p>Go to <strong>Settings</strong>.</p></li><li><p>Navigate to <strong>Privacy &gt; Tracking</strong>.</p></li><li><p>Toggle <strong>Allow Apps to Request to Track</strong> off, then select <strong>Ask Apps to Stop Tracking</strong> in the prompt.</p><ol><li>You can toggle this back on at this point if you&#39;d like.</li></ol></li></ol><h2 id="find-my-android-device-id" tabindex="-1">Find my Android device ID <a class="header-anchor" href="#find-my-android-device-id" aria-label="Permalink to &quot;Find my Android device ID&quot;">​</a></h2><p>To find your AAID:</p><ol><li>Go to the <strong>Settings</strong> app on your device.</li><li>Navigate to <strong>Google Settings</strong>.</li><li>Select <strong>Ads</strong> — your AAID will be visible at the bottom of the screen.</li></ol><p>To reset your AAID:</p><ol><li>Go to the <strong>Settings</strong> app on your device.</li><li>Navigate to <strong>Google Settings</strong>.</li><li>Select <strong>Ads</strong>.</li><li>Select <strong>Reset advertising ID</strong>.</li></ol>',13)])])}const g=i(r,[["render",d]]);export{u as __pageData,g as default};
